package com.duoc.msgestion.controller; import com.duoc.msgestion.model.Producto; import com.duoc.msgestion.service.ProductoService; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.List; @RestController @RequestMapping("/api/productos") @CrossOrigin(origins = "*") public class ProductoController { @Autowired private ProductoService service; @GetMapping public List<Producto> obtenerTodos() { return service.listarTodosLosProductos(); } @PostMapping @ResponseStatus(HttpStatus.CREATED) public Producto crearNuevo(@RequestBody Producto producto) { return service.guardarProducto(producto); } }